    origin = request.headers.get('Origin', '*')
    
    # In production, validate against allowed origins
    if ALLOWED_ORIGINS != '*':
        allowed_list = [o.strip() for o in ALLOWED_ORIGINS.split(',')]
        if origin not in allowed_list:
            origin = allowed_list[0] if allowed_list else '*'
    
    response.headers['Access-Control-Allow-Origin'] = origin
    response.headers['Access-Control-Allow-Methods'] = 'GET, POST, PUT, DELETE, OPTIONS'
    response.headers['Access-Control-Allow-Headers'] = f'Content-Type, {API_KEY_HEADER}, {SIGNATURE_HEADER}, {TIMESTAMP_HEADER}'
    response.headers['Access-Control-Max-Age'] = '3600'
